class ValidationError(Exception):
    pass

def validate_age(age):
    if age < 0:
        raise ValidationError("Age cannot be negative.")

try:
    validate_age(-5)
except ValidationError as e:
    print(f"Validation error: {e}")

CREATE TABLE products (
    product_id INT PRIMARY KEY,
    product_name VARCHAR(100),
    quantity_in_stock INT DEFAULT 0
);

-- Example: Selling 3 Laptops
UPDATE products
SET quantity_in_stock = quantity_in_stock - 3
WHERE product_id = 1;

INSERT INTO inventory_log (product_id, change_quantity, transaction_type)
VALUES (1, -3, 'sale');

-- Example: Restocking 20 Smartphones
UPDATE products
SET quantity_in_stock = quantity_in_stock + 20
WHERE product_id = 2;

INSERT INTO inventory_log (product_id, change_quantity, transaction_type)
VALUES (2, 20, 'restock');

SELECT product_id, product_name, quantity_in_stock
FROM products
ORDER BY product_name;

